{
  "schema_version": "1.0.0",
  "template_version": "1.0.0",
  "placeholder_tokens": ["<", "TBD", "TODO", "未定"],
  "not_applicable_format": "N/A: <reason>",
  "common_frontmatter": {
    "template": "common-frontmatter.md",
    "required": ["graph_node_id", "artifact_kind", "artifact_subtypes", "title", "project_id", "domain", "status", "priority", "start_date", "target_date", "iteration", "owners", "tags", "file_path", "template_id", "template_version", "confirmation_status", "evaluation_status", "confirmation_evidence", "source_lineage", "created_at", "updated_at", "depends_on", "related_nodes", "resource_scope", "purpose", "goal", "scope_in", "scope_out", "acceptance", "architecture_refs", "parent_feature", "feature_package_id", "phase_ref", "classification_confidence", "classification_reason", "classification_candidates", "tracker_binding", "beads_linkage", "github_publication", "issue_linkage", "github_project_linkages", "pull_request_linkages", "execution_contexts", "completion_evidence", "implementation_readiness"]
  },
  "artifacts": {
    "issue": {
      "template": "issue.md",
      "required_sections": ["概要", "背景と問題", "現在の挙動", "期待する挙動", "再現手順またはユースケース", "影響と優先度", "スコープ", "関連グラフ", "受入条件", "検証証跡"]
    },
    "task": {
      "template": "task.md",
      "required_sections": ["目的", "背景", "入力と前提条件", "出力と成果物", "依存関係", "実装対象", "Write scope と競合制約", "GitHub publication", "実行手順", "受入条件", "検証方法", "リスクとロールバック", "Handoff"],
      "conditional_templates": {"system_development": "system-task-spec.md"},
      "conditional_required_sections": {"system_development": ["Workstream applicability", "Architecture and deploy unit", "Verification and evidence", "Rollout and rollback", "Tracker publication and completion intent"]}
    },
    "document": {
      "template": "document.md",
      "required_sections": ["目的", "対象読者", "要約", "本文", "決定事項", "運用・更新方法", "関連資料", "変更履歴"]
    },
    "specification": {
      "template": "specification.md",
      "required_sections": ["目的と成功状態", "スコープ", "用語と主体", "ユースケースとユーザーフロー", "機能要件", "非機能要件", "UI・状態遷移", "ビジネスルールと検証", "API契約", "データモデル", "認証・認可", "エラー・例外・回復", "イベント・非同期処理", "可観測性", "互換性・移行・リリース", "テストと受入条件", "未決事項"],
      "conditional_templates": {"api_changed": "api-contract.md"}
    },
    "architecture": {
      "template": "architecture.md",
      "required_sections": ["Architecture overview", "Context and drivers", "Goals and non-goals", "System context and boundaries", "Container and component view", "Cross-cutting contracts", "Subtype architecture", "Architecture decisions", "Delivery, migration and rollback", "Risks and verification"],
      "subtype_templates": {
        "frontend": "architecture-frontend.md",
        "backend": "architecture-backend.md",
        "infrastructure": "architecture-infrastructure.md",
        "data": "architecture-data.md",
        "security": "architecture-security.md"
      },
      "subtype_policy": "one_or_more_or_explicit_not_applicable"
    },
    "feature": {
      "template": "feature.md",
      "required_sections": ["目的", "到達状態", "スコープ", "受入", "アーキテクチャ参照", "機能間依存", "Handoff"],
      "note": "マクロ層の機能単位ノード。purpose/goal/scope_in/scope_out/acceptance/architecture_refsを本文床として保持し、機能間依存は既存depends_onを流用する (MM-01, MM-11)。細タスク仕様書生成は external plugin system-dev-planner (ミクロ層) へ委譲し本テンプレートでは扱わない"
    }
  },
  "graph_projection": {
    "template": "task-graph-node.md",
    "required_fields": ["graph_node_id", "artifact_kind", "file_path", "goal", "depends_on", "touches", "acceptance", "verification", "handoff_route"],
    "root_map": {
      "issue": "issues/",
      "task": "tasks/",
      "specification": "specs/",
      "architecture": "architecture/",
      "feature": "features/",
      "document": "docs/"
    }
  },
  "system_plan": {
    "phase_template": null,
    "legacy_phase_template": "system-phase-spec.md (compatibility only; runtime emission forbidden)",
    "task_overlay": "system-task-spec.md",
    "task_overlay_status": "pointer_to_canonical",
    "task_overlay_canonical": "plugin-plans/system-dev-planner/references/system-task-spec-template.md",
    "runtime_emission_owner": "system-dev-planner (dev-graph はruntime task specをemitせず登録・投影・完了収束のみ担う。templates/system-task-spec.md は後方互換のpointerで、節構成・必須フィールドの正本は canonical 側)",
    "system_task_required_fields": ["parent_feature", "feature_package_id", "phase_ref"],
    "rule": "one feature execution package contains exactly 13 executable task artifacts, one for each P01..P13; no separate phase-document set and no variable-N canonical tasks",
    "feature_boundary": "system-dev-planner consumes exactly one dev-graph feature node (purpose/goal/scope_in/scope_out/acceptance/architecture_refs) as structured input context and never creates feature nodes; its promoted typed tasks register back into dev-graph with parent_feature=当該feature (MM-11)"
  },
  "readiness": {
    "states": ["complete", "incomplete", "not_applicable"],
    "complete_when": "all required fields and sections are substantive, all referenced nodes resolve, and conditional templates are satisfied",
    "fail_closed_on": ["missing_required_frontmatter", "missing_required_section", "placeholder_only_section", "unresolved_graph_reference", "conditional_template_missing", "path_parity_error"]
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "graph-node.schema.json",
  "title": "dev-graph タスクグラフノード (draft)",
  "description": "run-plugin-dev-plan が manual-apply artifact として出力する schema draft。後段 builder または人手承認で plugins/dev-graph/schemas/graph-node.schema.json へ適用する。issue/task/specification/architecture/feature/document の各成果物を単一グラフ構造で表現し、issues/tasks/specs/architecture/features/docs の正規ディレクトリへ自動routingする。feature はマクロ層 (purpose/goal/scope/acceptance/architecture_refs) を保持し、細タスク仕様書生成は external plugin system-dev-planner (ミクロ層) へ委譲する (MM-01)。",
  "type": "object",
  "required": [
    "graph_node_id",
    "artifact_kind",
    "artifact_subtypes",
    "title",
    "project_id",
    "domain",
    "status",
    "owners",
    "tags",
    "priority",
    "start_date",
    "target_date",
    "iteration",
    "created_at",
    "updated_at",
    "depends_on",
    "related_nodes",
    "resource_scope",
    "parent_feature",
    "feature_package_id",
    "phase_ref",
    "file_path",
    "template_id",
    "template_version",
    "confirmation_status",
    "evaluation_status",
    "confirmation_evidence",
    "source_lineage",
    "classification_confidence",
    "classification_reason",
    "classification_candidates",
    "github_publication",
    "issue_linkage",
    "tracker_binding",
    "beads_linkage",
    "github_project_linkages",
    "pull_request_linkages",
    "execution_contexts",
    "completion_evidence",
    "implementation_readiness"
  ],
  "properties": {
    "graph_node_id": {
      "type": "string",
      "minLength": 1,
      "description": "移動・再分類・GitHub同期後も変化しない論理identity。file_pathはこのIDを参照する可変projectionでありidentityに使わない"
    },
    "id": {
      "type": "string",
      "deprecated": true,
      "description": "後方互換alias。新規成果物ではgraph_node_idを正本とする"
    },
    "artifact_kind": {
      "type": "string",
      "enum": [
        "issue",
        "task",
        "specification",
        "architecture",
        "feature",
        "document"
      ],
      "description": "成果物種別。正規rootへ issue→issues/task→tasks/specification→specs/architecture→architecture/feature→features/document→docs と決定論写像する。feature はマクロ層の機能単位ノード (purpose/goal/scope_in/scope_out/acceptance/architecture_refs を第一級に保持、MM-01)"
    },
    "artifact_subtypes": {
      "type": "array",
      "items": {
        "type": "string",
        "enum": [
          "frontend",
          "backend",
          "infrastructure",
          "data",
          "security",
          "api"
        ]
      },
      "uniqueItems": true,
      "description": "architecture subtype または specification の conditional template。architecture は1種以上、非該当kindは空配列を許す"
    },
    "kind": {
      "type": "string",
      "deprecated": true,
      "enum": [
        "issue",
        "task",
        "specification",
        "architecture",
        "feature",
        "document"
      ],
      "description": "後方互換alias。新規成果物ではartifact_kindを正本とする"
    },
    "project_id": {
      "type": "string",
      "minLength": 1,
      "description": "横断分類用project identifier。物理top-levelを決めず、閾値超過時だけsecondary partitionに使う"
    },
    "domain": {
      "type": "string",
      "minLength": 1,
      "description": "横断分類用domain。1 leafが200件を超えた場合の第一partition key"
    },
    "tags": {
      "type": "array",
      "items": {
        "type": "string",
        "minLength": 1
      },
      "uniqueItems": true,
      "description": "物理配置から独立した横断検索タグ"
    },
    "priority": {
      "type": [
        "string",
        "null"
      ],
      "description": "tracker/Projectsへ投影可能なrepo-local priority。nullは未設定"
    },
    "start_date": {
      "type": [
        "string",
        "null"
      ],
      "format": "date"
    },
    "target_date": {
      "type": [
        "string",
        "null"
      ],
      "format": "date"
    },
    "iteration": {
      "type": [
        "string",
        "null"
      ],
      "description": "Projects iteration title等へ写像する安定した人間可読値"
    },
    "title": {
      "type": "string",
      "minLength": 1
    },
    "owners": {
      "type": "array",
      "items": {
        "type": "string",
        "minLength": 1
      },
      "description": "成果物の更新責任者"
    },
    "created_at": {
      "type": "string",
      "format": "date-time"
    },
    "updated_at": {
      "type": "string",
      "format": "date-time",
      "description": "id + updated_at がGitHub双方向同期(要件C4)の競合解決キー"
    },
    "status": {
      "type": "string",
      "enum": [
        "draft",
        "active",
        "blocked",
        "done",
        "closed",
        "tombstoned"
      ],
      "description": "全artifact共通workflow state。GitHub Issue openはactive、closeはclosedへ写像し、delete相当はtombstonedで物理削除しない"
    },
    "closed_at": {
      "type": [
        "string",
        "null"
      ],
      "format": "date-time",
      "description": "status=closed|tombstoned に遷移した時刻。close/delete のtombstone双方向伝播(要件C12)がこの時刻を記録する"
    },
    "depends_on": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "依存先ノードid配列。ready-set算出(要件C8)の入力。feature ノード間の機能間依存もこのフィールドを流用する (新フィールド不要・MM-01)"
    },
    "related_nodes": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "uniqueItems": true,
      "description": "順序依存を持たない関連ノード参照"
    },
    "resource_scope": {
      "type": "array",
      "items": {
        "type": "string",
        "pattern": "^(?!/)(?!.*(?:^|/)\\.\\.(?:/|$)).+$"
      },
      "description": "touches: このノードが触るファイル/ディレクトリパス配列。既定はディレクトリ単位、ノードがファイル単位を明示した場合はファイル単位を優先し、双方混在時は広い方(ディレクトリ単位)へフォールバックする。並列バッチのresource_scope重複回避(要件C10)の土台"
    },
    "purpose": {
      "type": [
        "string",
        "null"
      ],
      "description": "feature ノードがなぜ必要かの説明 (JTBD/価値)。artifact_kind=feature のとき非null必須、他kindはnull (MM-01)"
    },
    "goal": {
      "type": [
        "string",
        "null"
      ],
      "description": "feature ノードが達成する到達状態。旧 目標+ゴールの語彙を1本に統合した表現。artifact_kind=feature のとき非null必須、他kindはnull (MM-01)。program全体のgoalはgoal-spec.jsonが正本で、本フィールドは機能単位に閉じる"
    },
    "scope_in": {
      "type": "array",
      "items": {
        "type": "string",
        "minLength": 1
      },
      "description": "feature ノードのスコープ内。artifact_kind=feature のとき1件以上必須、他kindは空配列 (MM-01)"
    },
    "scope_out": {
      "type": "array",
      "items": {
        "type": "string",
        "minLength": 1
      },
      "description": "feature ノードのスコープ外。artifact_kind=feature のとき1件以上必須、他kindは空配列 (MM-01)"
    },
    "acceptance": {
      "type": "array",
      "items": {
        "type": "string",
        "minLength": 1
      },
      "description": "feature ノードが確実に実行したい観測可能な二値条件。artifact_kind=feature のとき1件以上必須、他kindは空配列 (MM-01)"
    },
    "architecture_refs": {
      "type": "array",
      "items": {
        "type": "string",
        "minLength": 1
      },
      "uniqueItems": true,
      "description": "feature ノードが参照する architecture ノードの graph_node_id 配列。artifact_kind=feature のとき1件以上必須、他kindは空配列 (MM-01)。system-spec-harness由来のarchitectureはlineage参照のみで複製しない (MM-12)"
    },
    "parent_feature": {
      "type": [
        "string",
        "null"
      ],
      "description": "task ノードが属する feature ノードの graph_node_id。artifact_kind=task かつ feature 由来のときのみ非null (feature文脈を持たない単発taskはnull可)。artifact_kind!=task では常にnull。順序依存のないrelated_nodesや複数依存を表すdepends_onとは別概念の単一親参照 (MM-03)"
    },
    "feature_package_id": {
      "type": ["string", "null"],
      "pattern": "^feature-package/[A-Za-z0-9._/-]+$",
      "description": "system-dev-plannerが1 featureから生成したexact 13 task package identity。feature由来taskは非null、他artifactと単発taskはnull"
    },
    "phase_ref": {
      "type": ["string", "null"],
      "enum": [null, "P01", "P02", "P03", "P04", "P05", "P06", "P07", "P08", "P09", "P10", "P11", "P12", "P13"],
      "description": "feature execution package内の一意phase slot。P01..P13各1件。feature由来task以外はnull"
    },
    "file_path": {
      "type": "string",
      "pattern": "^(issues|tasks|specs|architecture|features|docs)/.+\\.md$",
      "description": "全artifactが持つ正規root配下の人間可読Markdownへの参照。graph_node_idは不変、file_pathはrouting policyとpartition状態から再計算可能な派生値。feature は features/ 配下 (MM-02)"
    },
    "template_id": {
      "type": "string",
      "enum": [
        "issue",
        "task",
        "document",
        "specification",
        "architecture",
        "feature"
      ],
      "description": "artifact_kindから自動選択した基底テンプレート"
    },
    "template_version": {
      "type": "string",
      "pattern": "^[0-9]+\\.[0-9]+\\.[0-9]+$",
      "description": "生成時に使用したテンプレート契約版。正本更新時は既存文書を全書換せずmigration previewへ使う"
    },
    "confirmation_status": {
      "type": "string",
      "enum": [
        "draft",
        "confirmed",
        "superseded"
      ],
      "description": "内容確定状態。system plan入力はspecification/architectureがconfirmedであることを要求する"
    },
    "evaluation_status": {
      "type": "string",
      "enum": [
        "pending",
        "pass",
        "fail",
        "stale"
      ],
      "description": "独立評価状態。C14/C15/C04はpass以外をIssue起票・推薦・実装handoff対象にしない"
    },
    "confirmation_evidence": {
      "type": "object",
      "required": [
        "evaluator",
        "evidence_ref",
        "evaluated_digest"
      ],
      "properties": {
        "evaluator": {
          "type": [
            "string",
            "null"
          ]
        },
        "evidence_ref": {
          "type": [
            "string",
            "null"
          ]
        },
        "evaluated_digest": {
          "type": [
            "string",
            "null"
          ],
          "pattern": "^[a-f0-9]{64}$"
        }
      },
      "additionalProperties": false,
      "description": "confirmation/evaluationを同一artifact digestへpinしstale PASSを拒否する"
    },
    "source_lineage": {
      "type": "object",
      "required": [
        "origin_kind",
        "source_plugin",
        "source_path",
        "source_version",
        "source_digest",
        "imported_at"
      ],
      "properties": {
        "origin_kind": {
          "type": "string",
          "enum": [
            "manual",
            "github",
            "system-spec-harness",
            "system-dev-planner",
            "generated"
          ]
        },
        "source_plugin": {
          "type": [
            "string",
            "null"
          ]
        },
        "source_path": {
          "type": [
            "string",
            "null"
          ],
          "pattern": "^(?!/)(?!.*(?:^|/)\\.\\.(?:/|$)).+$"
        },
        "source_version": {
          "type": [
            "string",
            "null"
          ]
        },
        "source_digest": {
          "type": [
            "string",
            "null"
          ],
          "pattern": "^[a-f0-9]{64}$"
        },
        "imported_at": {
          "type": [
            "string",
            "null"
          ],
          "format": "date-time"
        }
      },
      "additionalProperties": false,
      "description": "引用・import元を追跡し、C19およびexternal plugin system-dev-planner由来のimportが外部正本を利用したことを検証する"
    },
    "classification_confidence": {
      "type": "number",
      "minimum": 0,
      "maximum": 1,
      "description": "artifact_kind/domain/project_id自動分類のconfidence。0.80以上かつ第2候補との差0.15以上で自動確定、それ未満はpreview後に確認"
    },
    "classification_reason": {
      "type": "string",
      "minLength": 1,
      "description": "自動分類の根拠。previewと監査証跡へ表示する"
    },
    "classification_candidates": {
      "type": "array",
      "items": {
        "type": "object",
        "required": [
          "artifact_kind",
          "confidence",
          "candidate_path"
        ],
        "properties": {
          "artifact_kind": {
            "$ref": "#/$defs/artifactKind"
          },
          "confidence": {
            "type": "number",
            "minimum": 0,
            "maximum": 1
          },
          "candidate_path": {
            "type": "string"
          }
        },
        "additionalProperties": false
      },
      "description": "previewに表示する上位候補。ユーザーへ保存先そのものを入力させない"
    },
    "issue_linkage": {
      "type": [
        "object",
        "null"
      ],
      "description": "GitHub Issue との紐付け。C14 (decompose) が起票した時点でissue_numberを書き込み、C03 (sync) はlinkage済みノードを新規起票せずupdated_at比較のみを行う (create→syncの起票非重複契約・要件C7)",
      "properties": {
        "issue_number": {
          "type": "integer"
